function buildCrossLinks(allEntries: EncyclopediaEntry[]): EncyclopediaEntry[] {
  const slugMap = new Map<string, EncyclopediaEntry>();
  for (const e of allEntries) {
    slugMap.set(e.slug, e);
  }

  for (const entry of allEntries) {
    const titleLower = entry.title.toLowerCase();
    const overviewLower = entry.overview.toLowerCase();
    const crossLinks: { slug: string; profession: string; title: string }[] = [];

    for (const [keyword, professions] of Object.entries(CROSS_LINK_MAP)) {
      if (titleLower.includes(keyword) || overviewLower.includes(keyword)) {
        for (const targetProf of professions) {
          if (targetProf === entry.profession) continue;
          const candidates = allEntries.filter(
            (e) => e.profession === targetProf &&
              (e.title.toLowerCase().includes(keyword) || e.overview.toLowerCase().includes(keyword))
          );
          for (const candidate of candidates.slice(0, 3)) {
            if (!crossLinks.find((l) => l.slug === candidate.slug)) {
              crossLinks.push({ slug: candidate.slug, profession: candidate.profession, title: candidate.title });
            }
          }
        }
      }
    }

    entry.crossLinks = crossLinks.slice(0, 10);
  }

  return allEntries;
}

export async function seedEncyclopediaEntries(): Promise<{ total: number; byProfession: Record<string, number>; crossLinksAdded: number }> {
  await pool.query(`ALTER TABLE encyclopedia_entries ADD COLUMN IF NOT EXISTS category TEXT`);
  await pool.query(`ALTER TABLE encyclopedia_entries ADD COLUMN IF NOT EXISTS topic_id VARCHAR`);
  await pool.query(`ALTER TABLE encyclopedia_entries ADD COLUMN IF NOT EXISTS seo_title TEXT`);
  await pool.query(`ALTER TABLE encyclopedia_entries ADD COLUMN IF NOT EXISTS seo_description TEXT`);
  await pool.query(`ALTER TABLE encyclopedia_entries ADD COLUMN IF NOT EXISTS seo_keywords TEXT[] DEFAULT '{}'`);
  await pool.query(`ALTER TABLE encyclopedia_entries ADD COLUMN IF NOT EXISTS cross_profession_links JSONB DEFAULT '[]'`);
  await pool.query(`CREATE INDEX IF NOT EXISTS idx_encyclopedia_profession ON encyclopedia_entries(profession)`);
  await pool.query(`CREATE INDEX IF NOT EXISTS idx_encyclopedia_status ON encyclopedia_entries(status)`);
  await pool.query(`CREATE INDEX IF NOT EXISTS idx_encyclopedia_category ON encyclopedia_entries(profession, category)`);

  const existing = await pool.query(`SELECT COUNT(*)::int AS cnt FROM encyclopedia_entries`);
  if (existing.rows[0].cnt > 100) {
    console.log(`[Encyclopedia] Already has ${existing.rows[0].cnt} entries, skipping seed`);
    return { total: existing.rows[0].cnt, byProfession: {}, crossLinksAdded: 0 };
  }

  console.log("[Encyclopedia] Generating entries...");
  let allEntries: EncyclopediaEntry[] = [];
  allEntries.push(...makeParamedicEntries());
  allEntries.push(...makeRRTEntries());
  allEntries.push(...makeMLTEntries());
  allEntries.push(...makeImagingEntries());
  allEntries.push(...makeSocialWorkEntries());
  allEntries.push(...makePsychotherapistEntries());
  allEntries.push(...makeAddictionsEntries());
  allEntries.push(...makeOTEntries());

  console.log(`[Encyclopedia] Generated ${allEntries.length} entries, building cross-links...`);
  allEntries = buildCrossLinks(allEntries);

  let crossLinksAdded = 0;
  for (const e of allEntries) {
    const cl = (e as any).crossLinks || [];
    if (Array.isArray(cl) && cl.length > 0) crossLinksAdded++;
  }

  console.log(`[Encyclopedia] Inserting ${allEntries.length} entries with ${crossLinksAdded} cross-linked entries...`);

  const BATCH_SIZE = 50;
  for (let i = 0; i < allEntries.length; i += BATCH_SIZE) {
    const batch = allEntries.slice(i, i + BATCH_SIZE);
    const values: string[] = [];
    const params: any[] = [];
    let pIdx = 1;

    for (const e of batch) {
      values.push(`($${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++}, $${pIdx++})`);
      params.push(
        e.profession, e.domain, e.title, e.slug, e.overview, e.mechanism || null,
        e.clinicalRelevance || null, e.signsSymptoms || null, e.assessment || null,
        e.management || null, e.complications || null,
        JSON.stringify(typeof e.clinicalPearls === 'string' ? [{ text: e.clinicalPearls }] : []),
        JSON.stringify(typeof e.examPitfalls === 'string' ? [{ text: e.examPitfalls }] : []),
        JSON.stringify(e.faq || []), e.keywords || [],
        JSON.stringify((e as any).crossLinks || []),
        e.seoTitle || null, e.seoDescription || null
      );
    }

    await pool.query(
      `INSERT INTO encyclopedia_entries (profession, category, title, slug, overview, mechanism_physiology, clinical_relevance, signs_symptoms, assessment, management, complications, clinical_pearls, exam_pitfalls, faq_json, seo_keywords, cross_profession_links, seo_title, seo_description)
       VALUES ${values.join(", ")}
       ON CONFLICT (profession, slug) DO NOTHING`,
      params
    );

    if ((i + BATCH_SIZE) % 200 === 0 || i + BATCH_SIZE >= allEntries.length) {
      console.log(`[Encyclopedia] Inserted ${Math.min(i + BATCH_SIZE, allEntries.length)}/${allEntries.length}`);
    }
  }

  const byProfession: Record<string, number> = {};
  const countResult = await pool.query(`SELECT profession, COUNT(*)::int AS cnt FROM encyclopedia_entries GROUP BY profession`);
  for (const row of countResult.rows) {
    byProfession[row.profession] = row.cnt;
  }

  const totalResult = await pool.query(`SELECT COUNT(*)::int AS cnt FROM encyclopedia_entries`);
  const total = totalResult.rows[0].cnt;

  console.log(`[Encyclopedia] Seed complete: ${total} total entries`);
  console.log(`[Encyclopedia] By profession:`, JSON.stringify(byProfession));
  console.log(`[Encyclopedia] Entries with cross-links: ${crossLinksAdded}`);

  return { total, byProfession, crossLinksAdded };
}
